// Replace 0 with YOUR Telegram chat id so only you can query the server.
const ALLOWED_CHAT_ID = 0;
const m = ($input.first().json.message) || {};
const text = (m.text || '').trim();
const fromId = m.chat && m.chat.id;
if (ALLOWED_CHAT_ID && fromId !== ALLOWED_CHAT_ID) return [];
if (text !== '/status' && !text.startsWith('/status@')) return [];
return [{ json: {} }];

const d = JSON.parse((($input.first().json.stdout)||'{}').toString().trim());
const ic = v => String(v).startsWith('OK') ? '\u2705' : '\u274C';
const lines = [];
lines.push('\uD83D\uDDA5\uFE0F *VertiGuard \u2014 VPS status*');
lines.push(ic(d.nginx) + ' nginx');
lines.push(ic(d.mariadb) + ' MariaDB');
lines.push(ic(d.n8n) + ' n8n (Docker)');
lines.push(ic(d.web_main) + ' example.com');
lines.push(ic(d.web_app) + ' n8n.example.com');
lines.push('');
lines.push('\uD83D\uDCBD Disk: ' + d.disk_pct + '% \u00b7 \uD83E\uDDE0 RAM: ' + d.ram_pct + '%');
lines.push('\u23F1\uFE0F ' + (d.uptime || ''));
lines.push('\uD83D\uDD52 ' + (d.ts || ''));
return [{ json: { message: lines.join('\n') } }];
